using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// The HttpClient is injected via constructor DI — the SDK resolves it automatically
/// and it does NOT appear in the tool schema exposed to LLMs.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Fetch a single resource by its numeric ID.")]
    public async Task<string> GetResource(
        [Description("The numeric ID of the resource to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }

    [McpServerTool, Description("List resources, optionally filtered by user ID.")]
    public async Task<string> ListResources(
        [Description("Optional user ID to filter results")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Listing resources at {Url}", url);
        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }

    [McpServerTool, Description("Create a new resource with a title and body for a given user.")]
    public async Task<string> CreateResource(
        [Description("Title of the new resource")] string title,
        [Description("Body content of the new resource")] string body,
        [Description("User ID of the resource author")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating resource for user {UserId}", userId);
        var payload = new { title, body, userId };
        var response = await httpClient.PostAsJsonAsync("/posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }
}

